import './index.css';

import {
  Link
} from 'react-router-dom';

import NotesList
from '../../components/common/NotesList';

function TeacherDashboard() {

  const userString =
    localStorage.getItem('user');

  let user = {};

  try {

    user = userString
      ? JSON.parse(userString)
      : {};

  } catch (error) {

    console.log(error);

  }

  return (

    <div className="teacher-dashboard">

      {/* HEADER */}

      <div className="dashboard-header">

        <h1>
          Teacher Dashboard
        </h1>

        <button
          className="logout-btn"
          onClick={() => {

            localStorage.clear();

            window.location.href = '/';

          }}
        >

          Logout

        </button>

      </div>


      {/* USER CARD */}

      <div className="teacher-card">

        <h2>
          Welcome
          {' '}
          {user.name || 'Teacher'}
        </h2>

        <p>
          Email:
          {' '}
          {user.email}
        </p>

        <p>
          Role:
          {' '}
          {user.role}
        </p>

      </div>


      {/* DASHBOARD LINKS */}

      <div className="dashboard-grid">

        <Link
          to="/subjects"
          className="dashboard-box"
        >

          <h3>
            Subjects
          </h3>

          <p>
            Manage Subjects
          </p>

        </Link>


        <Link
          to="/add-student"
          className="dashboard-box"
        >

          <h3>
            Students
          </h3>

          <p>
            Add Students
          </p>

        </Link>


        <Link
          to="/add-marks"
          className="dashboard-box"
        >

          <h3>
            Marks
          </h3>

          <p>
            Add Student Marks
          </p>

        </Link>

      </div>


      {/* NOTES */}

      <NotesList />

    </div>

  );

}

export default TeacherDashboard;
